Last_actions = []
Last_actions2 = []
last_update = 0
thinking = False

def get_state(cells):
    s = ""
    for i in cells:
        s += str(i.cell_type)
    if QTable1.get(s) is not None:
        return s
    else:
        QTable1.update({s: [0, 0, 0, 0, 0, 0, 0, 0, 0]})
        return s
def get_state2(cells):
    s = ""
    for i in cells:
        s += str(i.cell_type)
    if QTable2.get(s) is not None:
        return s
    else:
        QTable2.update({s: [0, 0, 0, 0, 0, 0, 0, 0, 0]})
        return s

def move(cells, restarting, time):
    global last_update, thinking

    if not restarting and not gameloop.team1:
        if not thinking:
            last_update = time
            thinking = True

        if thinking and time > last_update + 300:
            state = get_state(cells)
            max_weight = random.randrange(9)
            while cells[max_weight].cell_type != 0:
                max_weight = random.randrange(9)
            for w in range(9):
                if QTable1[state][w] > QTable1[state][max_weight] and cells[w].cell_type == 0:
                    max_weight = w
                if random.randrange(0,300) == 1:
                    while cells[max_weight].cell_type != 0:
                        max_weight = random.randrange(9)
                    print("going random")
                    break
            cells[max_weight].cell_type = 2
            Last_actions.insert(0, [state, max_weight])
            gameloop.team1 = not gameloop.team1
            thinking = False
            last_update = time

    if not restarting and gameloop.team1:
        if not thinking:
            last_update = time
            thinking = True

        if thinking and time > last_update + 300:
            state = get_state2(cells)
            max_weight = random.randrange(9)
            while cells[max_weight].cell_type != 0:
                max_weight = random.randrange(9)
            for w in range(9):
                if QTable2[state][w] > QTable2[state][max_weight] and cells[w].cell_type == 0:
                    max_weight = w
                if random.randrange(0,300) == 1:
                    while cells[max_weight].cell_type != 0:
                        max_weight = random.randrange(9)
                    print("going random")
                    break
            cells[max_weight].cell_type = 1
            Last_actions2.insert(0, [state, max_weight])
            gameloop.team1 = not gameloop.team1
            thinking = False
            last_update = time

def reward():
    QTable1[Last_actions[0][0]][Last_actions[0][1]] += 0.1
    QTable1[Last_actions[1][0]][Last_actions[1][1]] += 0.1
    print("O", QTable1)
    Last_actions.clear()

def slap():
    if len(Last_actions) > 1:
        QTable1[Last_actions[0][0]][Last_actions[0][1]] -= 0.1
        QTable1[Last_actions[1][0]][Last_actions[1][1]] -= 0.1
    print("O", QTable1)
    Last_actions.clear()

def reward2():
    QTable2[Last_actions2[0][0]][Last_actions2[0][1]] += 0.1
    QTable2[Last_actions2[1][0]][Last_actions2[1][1]] += 0.1
    print("X", QTable2)
    Last_actions2.clear()

